    test_camp->set_owner( your_fac );

    // Add an expansion at the adjacent OMT tile so the camp covers two tiles.
    expansion_data e;
    e.type = base_camps::faction_decode( "faction_base" );
    e.pos = expansion_omt;
    test_camp->expansions[point_rel_omt::east] = e;

