        guy.set_fac( faction_your_followers );
        guy.set_attitude( NPCATT_FOLLOW );
        REQUIRE( guy.is_player_ally() );
        guy.rules.clear_flag( ally_rule::allow_pick_up );
        here.add_item_or_charges( adj, item( itype_sandwich_cheese_grilled ) );
