                           faction_your_followers, {}, "no_pickup" );
        here.add_item_or_charges( adj, item( itype_sandwich_cheese_grilled ) );
        CHECK( guy.find_nearby_food().empty() );
    }

    SECTION( "dry food found but scored lower when thirsty" ) {
