        // Nearest water behind glass walls (unreachable)
        tripoint_bub_ms blocked_at = guy.pos_bub() + tripoint( 2, 0, 0 );
        for( const tripoint_bub_ms &w : here.points_in_radius( blocked_at, 1 ) ) {
            if( w != blocked_at ) {
                here.ter_set( w, ter_t_wall_glass );
            }
