        here.ter_set( blocked_at, ter_t_water_sh );
        // Farther water on open ground (reachable)
        tripoint_bub_ms open_at = guy.pos_bub() + tripoint( 0, 3, 0 );
        here.ter_set( open_at, ter_t_water_sh );
        REQUIRE( here.passable( open_at ) );
