        const tripoint_bub_ms shelter = guy.pos_bub() + tripoint( 3, 0, 0 );
        here.ter_set( shelter, ter_t_floor );
        here.build_map_cache( 0 );
        const tripoint_bub_ms before = guy.pos_bub();

        guy.address_needs( 0 );

