        guy.assign_activity( harvest_activity_actor( tree, false ) );
        REQUIRE( guy.activity.id() == ACT_HARVEST );

        guy.set_moves( 100 );
        guy.move();

        CHECK( guy.activity.id() != ACT_HARVEST );
    }
}

