TEST_CASE( "snippet-tag-test" )
{
    // Actually used tags
    static const std::set<std::string> npc_talk_tags = {
        {
            "<name_b>", "<name_g>", "<hungry>", "<thirsty>",
            "<general_danger>", "<kill_npc>", "<combat_noise_warning>",
