    guy.set_all_parts_temp_conv( BODYTEMP_NORM );
    guy.set_all_parts_temp_cur( BODYTEMP_NORM );

    // Player 15 tiles west (>= 12, triggers "keep up").
    get_player_character().setpos( here, tripoint_bub_ms( 35, 50, 0 ) );
