// NPC assigned to expanded base should still be considered "at camp" when
// on any expansion tile, not just the original assigned tile.
TEST_CASE( "camp_expanded_base_within_camp", "[npc][camp]" )
{
    clear_map_without_vision();
    clear_avatar();
    get_player_character().camps.clear();
    map &m = get_map();
    const tripoint_abs_omt camp_omt = get_player_character().pos_abs_omt();
    const tripoint_abs_omt expansion_omt = camp_omt + point::east;
    const tripoint_abs_omt away_omt = camp_omt + point( 10, 0 );

    // Setup camp at camp_omt
    m.add_camp( camp_omt, "faction_camp" );
    std::optional<basecamp *> bcp = overmap_buffer.find_camp( camp_omt.xy() );
    REQUIRE( !!bcp );
    basecamp *test_camp = *bcp;
    test_camp->set_owner( your_fac );

    // Add an expansion at the adjacent OMT tile so the camp covers two tiles.
    expansion_data e;
    e.type = base_camps::faction_decode( "faction_base" );
    e.pos = expansion_omt;
    test_camp->expansions[point_rel_omt::east] = e;

    // Verify point_within_camp works for both tiles.
    CHECK( test_camp->point_within_camp( camp_omt ) );
    CHECK( test_camp->point_within_camp( expansion_omt ) );
    CHECK_FALSE( test_camp->point_within_camp( away_omt ) );

    // Spawn NPC assigned to the camp.
    npc &guy = spawn_npc( get_map().get_bub( project_to<coords::ms>( camp_omt ) ).xy(), "test_talker" );
    clear_character( guy, true );
    guy.set_fac( faction_your_followers );
    guy.mission = NPC_MISSION_CAMP_RESIDENT;
    guy.assigned_camp = camp_omt;
    guy.set_hunger( 0 );
    guy.set_thirst( 0 );
    guy.set_sleepiness( 0 );
    guy.set_stored_kcal( guy.get_healthy_kcal() );
    guy.regen_ai_cache();

    behavior::character_oracle_t oracle( &guy );

    // NPC at the original camp tile: should be idle (within camp), not away.
    CHECK( oracle.is_camp_idle( "" ) == behavior::status_t::running );
    CHECK( oracle.is_away_from_camp( "" ) == behavior::status_t::failure );
    CHECK( oracle.camp_work_urgency( "" ) > 0.0f );
    CHECK( oracle.free_time_urgency( "" ) > 0.0f );
    CHECK( oracle.return_to_camp_urgency( "" ) == 0.0f );

    // NPC at the expansion tile: should STILL be idle (within camp), not away.
    guy.setpos( get_map(), get_map().get_bub( project_to<coords::ms>( expansion_omt ) ) );
    guy.regen_ai_cache();
    CHECK( oracle.is_camp_idle( "" ) == behavior::status_t::running );
    CHECK( oracle.is_away_from_camp( "" ) == behavior::status_t::failure );
    CHECK( oracle.free_time_urgency( "" ) > 0.0f );
    CHECK( oracle.return_to_camp_urgency( "" ) == 0.0f );

    // NPC far away from the camp: should NOT be idle, should be away.
    guy.setpos( get_map(), get_map().get_bub( project_to<coords::ms>( away_omt ) ) );
    guy.regen_ai_cache();
    CHECK( oracle.is_camp_idle( "" ) == behavior::status_t::failure );
    CHECK( oracle.is_away_from_camp( "" ) == behavior::status_t::running );
    CHECK( oracle.free_time_urgency( "" ) == 0.0f );
    CHECK( oracle.return_to_camp_urgency( "" ) > 0.0f );
}

// NPC infinite loop when trying to forage/harvest terrain it can't interact with.
TEST_CASE( "npc_no_infinite_loop_foraging", "[npc][needs][forage]" )
{
    clear_map_without_vision();
    clear_avatar();
    get_player_character().camps.clear();
    get_player_character().setpos( get_map(), tripoint_bub_ms{ 10, 10, 0 } );
    get_weather().forced_temperature = 20_C;

    npc &guy = spawn_npc( { 50, 50 }, "test_talker" );
    clear_character( guy, true );

    // Extreme hunger bypasses the one_in(3) gate, deterministically tries to forage.
    guy.set_hunger( 300 );
    guy.set_thirst( 100 );
    guy.set_stored_kcal( 1000 );

    map &here = get_map();
    const tripoint_bub_ms adj = guy.pos_bub() + point::east;

    // Helper: run the NPC turn loop from do_turn.cpp, return true if it loops.
    const auto npc_loops = [&]() {
        guy.set_moves( 100 );
        int turns = 0;
        int real_count = 0;
        const int count_limit = std::max( 10, guy.get_moves() / 64 );
        while( !guy.is_dead() && !guy.in_sleep_state() &&
               guy.get_moves() > 0 && turns < 10 ) {
            const int moves = guy.get_moves();
            guy.move();
            if( moves == guy.get_moves() ) {
                real_count++;
                if( real_count > count_limit ) {
                    turns++;
                }
            }
        }
        return turns >= 10;
    };

    SECTION( "underbrush with items on it" ) {
        set_time_to_day();
        here.ter_set( adj, ter_t_underbrush );
        here.add_item_or_charges( adj, item( itype_2x4 ) );
        here.build_map_cache( 0 );

        CHECK_FALSE( npc_loops() );
        CHECK_FALSE( guy.has_effect( effect_npc_suspend ) );
    }

    SECTION( "harvestable tree - query_pick rejects non-avatar" ) {
        // Autumn so the apple tree has a harvest entry.
        calendar::turn = calendar::turn_zero + 2 * calendar::season_length() + 12_hours;
        here.ter_set( adj, ter_t_tree_apple );
        here.build_map_cache( 0 );
        REQUIRE( here.is_harvestable( adj ) );

        CHECK_FALSE( npc_loops() );
        CHECK_FALSE( guy.has_effect( effect_npc_suspend ) );
    }

    SECTION( "NO_NPC_FOOD NPC with stale hunger does not loop" ) {
        override_option no_food( "NO_NPC_FOOD", "true" );
        REQUIRE_FALSE( guy.needs_food() );

        // Stale hunger/thirst values that would trigger food-seeking
        // if the needs_food() guards were missing.
        guy.set_hunger( 300 );
        guy.set_thirst( 100 );
        guy.set_stored_kcal( 1000 );
        guy.i_add( item( itype_sandwich_cheese_grilled ) );

        set_time_to_day();
        here.build_map_cache( 0 );

        CHECK_FALSE( npc_loops() );
    }

    SECTION( "forage activity completes without backlog flooding" ) {
        set_time_to_day();
        here.ter_set( adj, ter_t_underbrush );
        here.build_map_cache( 0 );

        // Run several game turns. Each turn the BT may try to override the
        // forage activity with follow_player. The activity should complete
        // without endlessly re-assigning and flooding the backlog.
        for( int turn = 0; turn < 20; ++turn ) {
            guy.set_moves( 100 );
            guy.move();
        }
        CHECK( guy.backlog.size() < 10 );
    }
}

